module RefModule(  
    input [7:0] dividend,  
    input [7:0] divisor,  
    input clk,  
    input rst,  
    output reg [7:0] quotient,  
    output reg [7:0] remainder  
);  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            quotient <= 8'b0;  
            remainder <= 8'b0;  
        end else begin  
            if (divisor == 0) begin  
                quotient <= 8'hFF;  // maximum value for quotient  
                remainder <= dividend;  
            end else begin  
                quotient <= dividend / divisor;  
                remainder <= dividend % divisor;  
            end  
        end  
    end  
endmodule
